#!/usr/bin/env node

import fs from "node:fs";
import path from "node:path";
import { execSync } from "node:child_process";
import { fileURLToPath } from "node:url";

const PKM_ROOT = "/Volumes/Storage/PKM";
const OUTPUT_FILE = "/Volumes/Storage/PKM/Petrichor/VSCode.MOC.md";
const FORCE_INCLUDE = new Set(["Obsidian-Shared", "Proyect-Template", "Secrets"]);
const EXCLUDED_NAMES = new Set(["_gitops", ".git", ".obsidian", ".trash", ".venv", "node_modules"]);
const GENERIC_README_LINES = [
  "Scaffold generated by GitOps.",
  "Project scaffold generated by GitOps.",
];

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const repoRoot = path.resolve(__dirname, "../..");
const updateCommandPath = path.join(repoRoot, "automation/dashboard/update-vscode-moc.command");

function safeExec(command, cwd = PKM_ROOT) {
  try {
    return execSync(command, {
      cwd,
      encoding: "utf8",
      stdio: ["ignore", "pipe", "ignore"],
    }).trim();
  } catch {
    return "";
  }
}

function fileExists(targetPath) {
  try {
    fs.accessSync(targetPath, fs.constants.F_OK);
    return true;
  } catch {
    return false;
  }
}

function readFileSafe(targetPath) {
  try {
    return fs.readFileSync(targetPath, "utf8");
  } catch {
    return "";
  }
}

function listDirectories(targetPath) {
  try {
    return fs
      .readdirSync(targetPath, { withFileTypes: true })
      .filter(entry => entry.isDirectory() && !entry.name.startsWith("."))
      .map(entry => path.join(targetPath, entry.name));
  } catch {
    return [];
  }
}

function latestMtime(targetPath, depth = 2) {
  let latest = 0;

  function visit(currentPath, currentDepth) {
    if (currentDepth < 0) {
      return;
    }

    let stat;
    try {
      stat = fs.statSync(currentPath);
    } catch {
      return;
    }

    latest = Math.max(latest, stat.mtimeMs);

    if (!stat.isDirectory()) {
      return;
    }

    const base = path.basename(currentPath);
    if (base === ".git" || base === "node_modules" || base.startsWith(".")) {
      return;
    }

    let entries = [];
    try {
      entries = fs.readdirSync(currentPath, { withFileTypes: true });
    } catch {
      return;
    }

    for (const entry of entries) {
      visit(path.join(currentPath, entry.name), currentDepth - 1);
    }
  }

  visit(targetPath, depth);
  return latest;
}

function toDateStringFromMs(ms) {
  if (!ms) {
    return "-";
  }
  return new Date(ms).toISOString().slice(0, 10);
}

function normalizeRepoUrl(url) {
  if (!url) {
    return "-";
  }

  if (url.startsWith("git@github.com:")) {
    const suffix = url.replace("git@github.com:", "").replace(/\.git$/, "");
    return `https://github.com/${suffix}`;
  }

  return url.replace(/\.git$/, "");
}

function encodeTodoistContent(content) {
  return encodeURIComponent(content).replace(/%20/g, "%20");
}

function firstMatch(content, patterns) {
  for (const pattern of patterns) {
    const match = content.match(pattern);
    if (match?.[1]) {
      return match[1].trim();
    }
  }
  return "";
}

function extractReadmeObjective(projectPath) {
  const readmePath = path.join(projectPath, "README.md");
  const content = readFileSafe(readmePath);
  if (!content) {
    return { objective: "", source: "" };
  }

  const explicit = firstMatch(content, [
    /^##\s*(?:Objective|Objetivo|Overview|Purpose|About)\s*\n+([\s\S]*?)(?:\n## |\n# |$)/im,
    /^#\s+.+\n+([\s\S]*?)(?:\n## |\n# |$)/m,
  ]);

  if (explicit) {
    const line = explicit
      .split("\n")
      .map(item => item.trim())
      .find(item =>
        item &&
        !item.startsWith("-") &&
        !item.startsWith("```") &&
        !item.startsWith("#")
      );

    if (line && !GENERIC_README_LINES.includes(line)) {
      return { objective: line, source: "README.md" };
    }
  }

  return { objective: "", source: "" };
}

function extractManifestObjective(projectPath) {
  const packageJsonPath = path.join(projectPath, "package.json");
  if (fileExists(packageJsonPath)) {
    try {
      const parsed = JSON.parse(readFileSafe(packageJsonPath));
      if (parsed.description) {
        return { objective: String(parsed.description).trim(), source: "package.json" };
      }
    } catch {
      // Ignore malformed package.json for this dashboard use case.
    }
  }

  const pyprojectPath = path.join(projectPath, "pyproject.toml");
  const pyproject = readFileSafe(pyprojectPath);
  if (pyproject) {
    const description = firstMatch(pyproject, [/description\s*=\s*"([^"]+)"/]);
    if (description) {
      return { objective: description, source: "pyproject.toml" };
    }
  }

  return { objective: "", source: "" };
}

function inferObjective(projectName) {
  const normalized = projectName.toLowerCase();

  if (normalized.includes("job")) {
    return "Objetivo propuesto: construir un sistema gobernado para ejecucion de busqueda laboral de alta senal.";
  }
  if (normalized.includes("legal")) {
    return "Objetivo propuesto: operar un sistema legal gobernado para gestion de casos, conocimiento y decisiones.";
  }
  if (normalized.includes("mining")) {
    return "Objetivo propuesto: operar una plataforma gobernada para flujos blueprint-to-DXF/3D.";
  }
  if (normalized.includes("automation")) {
    return "Objetivo propuesto: centralizar automatizaciones compartidas y disciplina operativa reusable.";
  }
  if (normalized.includes("petrichor")) {
    return "Objetivo propuesto: desarrollar una herramienta o automatizacion basada en Node.js.";
  }
  if (normalized.includes("secret")) {
    return "Objetivo propuesto: organizar y resguardar activos sensibles con estructura controlada.";
  }
  if (normalized.includes("obsidian")) {
    return "Objetivo propuesto: integrar o automatizar flujos con Obsidian.";
  }
  if (normalized.includes("template")) {
    return "Objetivo propuesto: mantener una base reusable para nuevos proyectos.";
  }
  if (normalized.includes("gitops")) {
    return "Objetivo propuesto: estandarizar bootstrap, gobierno y release discipline para proyectos X.Ops.";
  }
  if (normalized.includes("prompt")) {
    return "Objetivo propuesto: versionar prompts y activos operativos para ejecucion asistida por AI.";
  }
  if (normalized.includes("devlog")) {
    return "Objetivo propuesto: registrar aprendizaje tecnico y evidencia de trabajo de desarrollo.";
  }

  return "Objetivo propuesto: desarrollar y organizar este proyecto tecnico.";
}

function extractObjective(projectPath, projectName) {
  const readmeResult = extractReadmeObjective(projectPath);
  if (readmeResult.objective) {
    return readmeResult;
  }

  const manifestResult = extractManifestObjective(projectPath);
  if (manifestResult.objective) {
    return manifestResult;
  }

  return { objective: inferObjective(projectName), source: "inferred" };
}

function extractCriticalTask(projectPath, projectName) {
  const operationalCandidates = [
    path.join(projectPath, "docs", `${projectName}.Operational.md`),
    path.join(projectPath, "docs", `${projectName}.ControlCenter.md`),
    path.join(projectPath, "TODO.md"),
  ];

  for (const candidate of operationalCandidates) {
    const content = readFileSafe(candidate);
    if (!content) {
      continue;
    }

    const nextAction = firstMatch(content, [
      /next_actions:\s*\["([^"]+)"/i,
      /##\s*Next Actions[\s\S]*?\n1\.\s+([^\n]+)/i,
      /##\s*Urgent Improvement Contracts[\s\S]*?\n\|[^\n]+\|\n\|[^\n]+\|\n\|[^\n]+\|[^\n]+\|[^\n]+\|[^\n]+\|\s*([^\|]+)\|/i,
      /^-\s+\[\s\]\s+([^\n]+)/im,
    ]);

    if (nextAction) {
      return nextAction.replace(/\s+/g, " ").trim();
    }
  }

  if (!safeExec("git remote get-url origin", projectPath)) {
    return "Conectar repositorio remoto y dejar evidencia operativa minima.";
  }

  const readmeObjective = extractReadmeObjective(projectPath).objective;
  if (!readmeObjective) {
    return "Definir objetivo explicito en README para alinear decisiones y seguimiento.";
  }

  return "<++>";
}

function suggestNextStep(projectPath, projectName, criticalTask, objectiveSource) {
  if (criticalTask && criticalTask !== "<++>") {
    if (/README/i.test(criticalTask)) {
      return "Formalizar el objetivo del proyecto en README y reflejarlo en sus MOCs operativos.";
    }
    if (/schema|contract|harness|run-log|handoff|state/i.test(criticalTask)) {
      return "Cerrar primero los contratos operativos basicos antes de ampliar automatizaciones.";
    }
    if (/remote|repo/i.test(criticalTask)) {
      return "Conectar Git y governance minima para evitar trabajo sin trazabilidad.";
    }
    return criticalTask.charAt(0).toUpperCase() + criticalTask.slice(1);
  }

  if (objectiveSource === "inferred") {
    return `Definir un objetivo explicito en README y enlazar [[${projectName}.Tools]], [[${projectName}.Workflows]] y [[${projectName}.Agents]].`;
  }

  return "Revisar el valor principal del repositorio y priorizar la siguiente mejora con mayor impacto operativo.";
}

function hasOpenBlocker(projectPath) {
  const operationalFiles = [
    path.join(projectPath, "docs", `${path.basename(projectPath)}.Operational.md`),
    path.join(projectPath, "docs", `${path.basename(projectPath)}.ControlCenter.md`),
  ];

  return operationalFiles.some(filePath => {
    const content = readFileSafe(filePath);
    return /\|\s*Blocker\s*\|/i.test(content) || /Status:\s*Open/i.test(content);
  });
}

function computeState(lastUpdate, projectPath) {
  if (hasOpenBlocker(projectPath)) {
    return "Bloqueado";
  }

  if (lastUpdate === "-") {
    return "Dormido";
  }

  const diffDays = Math.floor((Date.now() - Date.parse(lastUpdate)) / 86400000);
  if (diffDays <= 14) {
    return "Activo";
  }
  if (diffDays <= 60) {
    return "En revision";
  }
  return "Dormido";
}

function hasProjectSignals(projectPath, depthFromRoot) {
  if (FORCE_INCLUDE.has(path.basename(projectPath))) {
    return true;
  }

  if (fileExists(path.join(projectPath, ".git"))) {
    return true;
  }
  if (fileExists(path.join(projectPath, ".vscode"))) {
    return true;
  }
  if (fileExists(path.join(projectPath, "README.md"))) {
    return true;
  }
  if (fileExists(path.join(projectPath, ".obsidian")) && depthFromRoot <= 1) {
    return true;
  }
  if (fileExists(path.join(projectPath, "docs")) && depthFromRoot <= 1) {
    return true;
  }

  return false;
}

function hasNestedProjectSignals(projectPath) {
  return (
    fileExists(path.join(projectPath, ".git")) ||
    fileExists(path.join(projectPath, ".vscode")) ||
    fileExists(path.join(projectPath, ".obsidian"))
  );
}

function discoverProjects() {
  const discovered = new Map();
  const topLevelDirs = listDirectories(PKM_ROOT)
    .filter(dirPath => !EXCLUDED_NAMES.has(path.basename(dirPath)));

  for (const dirPath of topLevelDirs) {
    if (hasProjectSignals(dirPath, 1)) {
      discovered.set(dirPath, true);
    }

    for (const childPath of listDirectories(dirPath)) {
      if (EXCLUDED_NAMES.has(path.basename(childPath))) {
        continue;
      }
      if (hasNestedProjectSignals(childPath)) {
        discovered.set(childPath, true);
      }
    }
  }

  return [...discovered.keys()].sort();
}

function computeProjectRecord(projectPath) {
  const projectName = path.basename(projectPath);
  const commitDate = safeExec("git log -1 --format=%cd --date=short", projectPath) || "-";
  const repoUrl = normalizeRepoUrl(safeExec("git remote get-url origin", projectPath));
  const latestFsDate = toDateStringFromMs(latestMtime(projectPath, 2));
  const lastUpdate = [commitDate, latestFsDate].filter(item => item !== "-").sort().slice(-1)[0] || "-";
  const state = computeState(lastUpdate, projectPath);
  const { objective, source } = extractObjective(projectPath, projectName);
  const criticalTask = extractCriticalTask(projectPath, projectName);
  const todoistTask = criticalTask === "<++>"
    ? "<++>"
    : `[${criticalTask}](todoist://addtask?content=${encodeTodoistContent(`${projectName} - ${criticalTask}`)})`;
  const nextStep = suggestNextStep(projectPath, projectName, criticalTask, source);

  return {
    projectName,
    projectPath,
    commitDate,
    lastUpdate,
    state,
    objective,
    source,
    criticalTask: todoistTask,
    nextStep,
    repoUrl,
  };
}

function escapePipes(value) {
  return String(value).replace(/\|/g, "\\|");
}

function buildRow(record) {
  const vaultHome = `[[${record.projectName}.MOC]]`;
  const vscodeLink = `[${record.projectName}](vscode://file${record.projectPath})`;
  const toolsLink = `[[${record.projectName}.Tools]]`;
  const workflowsLink = `[[${record.projectName}.Workflows]]`;
  const agentsLink = `[[${record.projectName}.Agents]]`;
  const repoLink = record.repoUrl === "-" ? "-" : `[repo](${record.repoUrl})`;

  return `| ${vaultHome} | ${vscodeLink} | ${toolsLink} | ${workflowsLink} | ${agentsLink} | ${record.commitDate} | ${record.lastUpdate} | ${record.state} | ${escapePipes(record.objective)} | ${record.source} | ${escapePipes(record.criticalTask)} | ${escapePipes(record.nextStep)} | ${repoLink} |`;
}

function render(records) {
  const generatedDate = new Date().toISOString().slice(0, 10);
  const rows = records.map(buildRow).join("\n");

  return `# MOC - Proyectos VS Code (Auto)

Generado: ${generatedDate}

## Criterio de objetivo
- Primero: README
- Segundo: metadata del manifiesto del stack
- Tercero: objetivo propuesto automaticamente

## Registro maestro

| Vault Home | VSCode | Tools | Workflows | Agents AI | Ultimo Commit | Ultimo Update | Estado | Objetivo del Proyecto | Fuente Objetivo | Tarea Critica | Proximo Paso | Repo |
| ---- | ---- | ---- | ---- | ---- | ---- | ---- | ---- | ---- | ---- | ---- | ---- | ---- |
${rows}

## Notas operativas
- "Fuente Objetivo" indica si el objetivo vino del README, del manifiesto o fue inferido.
- "Tarea Critica" crea una tarea en Todoist mediante deep link cuando existe una prioridad clara.
- Si la fuente es "inferred", conviene corregir ese proyecto y dejar un objetivo explicito en su README.
- El link del proyecto abre la carpeta directamente en VS Code.

## Update

Use este boton en Obsidian para regenerar el listado maestro de proyectos VS Code:

\`\`\`button
name Update VSCode MOC
type link
action file://${updateCommandPath}
color blue
\`\`\`

Fallback shell directo:

\`\`\`bash
bash ${path.join(repoRoot, "automation/dashboard/update-vscode-moc.sh")}
\`\`\`
`;
}

function main() {
  const records = discoverProjects()
    .map(computeProjectRecord)
    .sort((a, b) => {
      if (a.lastUpdate === "-" && b.lastUpdate === "-") {
        return a.projectName.localeCompare(b.projectName);
      }
      if (a.lastUpdate === "-") {
        return 1;
      }
      if (b.lastUpdate === "-") {
        return -1;
      }
      return b.lastUpdate.localeCompare(a.lastUpdate) || a.projectName.localeCompare(b.projectName);
    });

  fs.writeFileSync(OUTPUT_FILE, render(records), "utf8");
  process.stdout.write(`Updated ${OUTPUT_FILE}\n`);
}

main();
